    public static bool TryGet(string culture, string key, out string? message)
    {
        message = null;
        if (!Messages.TryGetValue(key, out Dictionary<string, string>? cultures))
        {
            return false;
        }

        if (cultures.TryGetValue(culture, out string? exact))
        {
            message = exact;
            return true;
        }

        if (culture.Length >= 2 && cultures.TryGetValue(culture[..2], out string? twoLetter))
        {
            message = twoLetter;
            return true;
        }

        return cultures.TryGetValue("en-US", out message);
    }
